#include<bits/stdc++.h>
using namespace std;
int a [200];
int main() {
	int n, m;
	cin >> n >> m;
	for (int i = 1; i <= n - 1; i++) a[i] = i + 1;
	a[n] = 1;
	int prev = 1, now = 1;
	while ((n--) > 1) {
		for (int i = 1; i < m; i++) {
			prev = now;
			now = a[now];
		}
		printf("%d ", now);
		a[prev] = a[now];
		now = a[prev];
	}
	cout << now;
	return 0;
}
